import { lerp, clamp, ease, RX, RY } from "./ScrollHero";

export default function Card({ card, progress }) {
  const rad = (card.angle * Math.PI) / 180;

  // Start position: on the horizontal oval
  const ox = Math.cos(rad) * RX; // vw
  const oy = -Math.sin(rad) * RY; // vh (CSS Y is inverted)

  // Exit direction: radially outward, scaled way off-screen
  const mag = Math.sqrt(ox * ox + oy * oy) || 1;
  const EX = (ox / mag) * 130;
  const EY = (oy / mag) * 130;

  // Movement starts at 35% scroll, ends at 90%
  const t = ease(clamp((progress - 0.35) / 0.55, 0, 1));

  const tx = lerp(ox, EX, t);
  const ty = lerp(oy, EY, t);
  // Fade out from 65%–95% scroll
  const opacity = lerp(1, 0, clamp((progress - 0.65) / 0.3, 0, 1));

  return (
    <div
      style={{
        position: "absolute",
        left: `calc(50% + ${tx}vw)`,
        top: `calc(50% + ${ty}vh)`,
        transform: `translate(-50%, -50%) rotate(${card.rotate}deg)`,
        opacity,
        zIndex: card.z,
        willChange: "transform, opacity",
        pointerEvents: "none",
      }}
    >
      <div
        style={{
          background: "white",
          borderRadius: 18,
          width: 128,
          paddingTop: 8,
          paddingBottom: 14,
          paddingLeft: 14,
          paddingRight: 14,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: 8,
          boxShadow:
            "0 10px 36px rgba(0,0,0,0.25), 0 2px 8px rgba(0,0,0,0.10)",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {/* Colored top accent bar */}
        <div
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            height: 5,
            background: card.accent,
            borderRadius: "18px 18px 0 0",
          }}
        />

        {/* Icon */}
        <div
          style={{
            width: 60,
            height: 60,
            background: "#f5f3ff",
            borderRadius: 12,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 28,
            marginTop: 6,
          }}
        >
          {card.emoji}
        </div>

        {/* Skeleton lines */}
        <div
          style={{
            width: 78,
            height: 7,
            borderRadius: 4,
            background: "#e2e8f0",
          }}
        />
        <div
          style={{
            width: 58,
            height: 7,
            borderRadius: 4,
            background: "#ede9fe",
          }}
        />

        {/* Label */}
        <span
          style={{
            fontSize: 10,
            fontWeight: 800,
            color: card.accent,
            letterSpacing: 0.7,
            textTransform: "uppercase",
            marginTop: 2,
          }}
        >
          {card.label}
        </span>
      </div>
    </div>
  );
}
